import { loader } from "fumadocs-core/source";
// `collections/server` is generated by the fumadocs-mdx vite plugin into
// `.source` (aliased in tsconfig). It exists once `react-router dev`/`build` or
// the fumadocs-mdx generator has run.
import { docs } from "collections/server";

// The single docs source: page tree, page lookup by slug, and search index all
// derive from this. `baseUrl: "/docs"` maps content/docs/<slug>.mdx → /docs/<slug>.
export const source = loader({
  baseUrl: "/docs",
  source: docs.toFumadocsSource(),
});
